    let mut conn = sqlx::SqliteConnection::connect("sqlite::memory:").await?;

    migrator.run(&mut conn).await?;
    let before = sqlite_schema_fingerprint(&mut conn).await?;

    sqlx::query("DROP TABLE IF EXISTS _sqlx_migrations")
        .execute(&mut conn)
