pub type StorageResult<T> = Result<T, StorageError>;

/// Unified storage error type so callers don't leak provider-specific details.
#[derive(Debug, Error)]
pub enum StorageError {
    #[error("not found: {0}")]
    NotFound(&'static str),
    #[error("conflict: {0}")]
    Conflict(&'static str),
    #[error("validation failed: {0}")]
    Validation(&'static str),
    #[error("mutation guard blocked: {0}")]
    Guard(&'static str),
    #[error("not implemented: {0}")]
    NotImplemented(&'static str),
    #[error("serialization error: {0}")]
    Serialization(String),
    /// Opaque database error - hides provider-specific types [Â§2.3.12.3 Trait Purity]
    #[error("database error: {0}")]
    Database(String),
    /// Opaque migration error - hides provider-specific types [Â§2.3.12.3 Trait Purity]
    #[error("migration error: {0}")]
    Migration(String),
}

// [Â§2.3.12.3] Manual From impl to convert sqlx::Error -> StorageError::Database
// This preserves the error message while hiding the sqlx type from public API.
impl From<sqlx::Error> for StorageError {
    fn from(err: sqlx::Error) -> Self {
        StorageError::Database(err.to_string())
    }
}

// [Â§2.3.12.3] Manual From impl to convert MigrateError -> StorageError::Migration
// This preserves the error message while hiding the sqlx::migrate type from public API.
impl From<sqlx::migrate::MigrateError> for StorageError {
    fn from(err: sqlx::migrate::MigrateError) -> Self {
        StorageError::Migration(err.to_string())
    }
}

impl From<serde_json::Error> for StorageError {
    fn from(value: serde_json::Error) -> Self {
        StorageError::Serialization(value.to_string())
    }
}

