                    "#,
                )
                .bind(workspace_id)
                .bind(limit_i64)
                .bind(offset_i64)
                .fetch_all(&self.pool)
                .await?;

                let mut groups: Vec<LoomViewGroup> = Vec::new();
                for row in group_rows {
                    let edge_type_raw: String = row.get("edge_type");
                    let target_block_id: String = row.get("target_block_id");
                    let edge_type = LoomEdgeType::from_str(edge_type_raw.as_str())?;

                    let rows = sqlx::query(
                        r#"
                        SELECT
                            b.block_id,
                            b.workspace_id,
                            b.content_type,
                            b.document_id,
                            b.asset_id,
                            b.title,
                            b.original_filename,
                            b.content_hash,
                            b.pinned,
                            b.journal_date,
                            b.created_at,
                            b.updated_at,
                            b.imported_at,
                            b.backlink_count,
                            b.mention_count,
                            b.tag_count,
                            b.derived_json,
                            b.preview_status,
                            b.thumbnail_asset_id,
                            b.proxy_asset_id
                        FROM loom_edges e
                        JOIN loom_blocks b
                          ON b.workspace_id = e.workspace_id AND b.block_id = e.source_block_id
                        LEFT JOIN assets a
                          ON a.workspace_id = b.workspace_id AND a.asset_id = b.asset_id
                        WHERE e.workspace_id = $1
                          AND e.edge_type = $2
                          AND e.target_block_id = $3
                        ORDER BY b.updated_at DESC
                        LIMIT 100
                        "#,
                    )
                    .bind(workspace_id)
                    .bind(edge_type.as_str())
                    .bind(&target_block_id)
                    .fetch_all(&self.pool)
                    .await?;

                    let blocks: Vec<LoomBlock> = rows
                        .into_iter()
                        .map(map_loom_block)
                        .collect::<StorageResult<Vec<_>>>()?;

                    groups.push(LoomViewGroup {
                        edge_type,
                        target_block_id,
                        blocks,
                    });
                }

                Ok(LoomViewResponse::Sorted { groups })
            }
        }
    }

